mapper.select:
SELECT decision_id, event_id, user_id, action_type, scenario,
       result, reason_code, request_hash, signals_json, actions_json,
       ext_json, trace_id, create_time, update_time
FROM risk_decision_log
WHERE 1=1

    AND user_id = #{userId}


    AND action_type = #{actionType}


    AND scenario = #{scenario}


    AND result = #{result}


    AND create_time >= #{beginTime}


    AND create_time <= #{endTime}

ORDER BY create_time DESC, decision_id DESC
LIMIT #{limit} OFFSET #{offset}
